import type {
	CriterionDefinition,
	PlotRawMetricValue,
	PlotRecord,
} from "@portugal/domain-shared";

/** Number of structured plot fields counted toward completeness (name through utilities flags). */
export const PLOT_PROFILE_COMPLETENESS_METADATA_SLOTS = 10;

function isCriterionRawFilled(
	value: PlotRawMetricValue | undefined,
	ruleType: CriterionDefinition["rule"]["type"],
): boolean {
	if (value === undefined) {
		return false;
	}
	if (ruleType === "numeric") {
		return typeof value === "number" && Number.isFinite(value);
	}
	if (ruleType === "qualitative") {
		return typeof value === "string" && value.trim().length > 0;
	}
	return Array.isArray(value) && value.length > 0;
}

function countMetadataFilled(plot: PlotRecord): number {
	let n = 0;
	if (plot.name.trim().length > 0) {
		n++;
	}
	if (plot.address.trim().length > 0) {
		n++;
	}
	if (plot.region !== undefined && plot.region.trim().length > 0) {
		n++;
	}
	if (plot.municipality !== undefined && plot.municipality.trim().length > 0) {
		n++;
	}
	const lat = plot.location?.lat;
	const lng = plot.location?.lng;
	if (
		typeof lat === "number" &&
		typeof lng === "number" &&
		Number.isFinite(lat) &&
		Number.isFinite(lng)
	) {
		n++;
	}
	if (plot.askingPriceEur !== undefined && Number.isFinite(plot.askingPriceEur)) {
		n++;
	}
	if (plot.koStatus !== undefined && plot.koStatus.trim().length > 0) {
		n++;
	}
	if (plot.buildableYn !== undefined) {
		n++;
	}
	if (plot.roadAccessYn !== undefined) {
		n++;
	}
	if (plot.utilitiesBasicYn !== undefined) {
		n++;
	}
	return n;
}

/**
 * How complete a plot record is for scoring and detail display: structured
 * metadata plus one slot per active scoring criterion with a filled raw metric.
 */
export function computePlotProfileCompleteness(
	plot: PlotRecord,
	criteria: readonly CriterionDefinition[],
): { filled: number; total: number; percentage: number } {
	const metadataFilled = countMetadataFilled(plot);
	const metricsTotal = criteria.length;
	let metricsFilled = 0;
	for (const c of criteria) {
		if (isCriterionRawFilled(plot.rawMetrics[c.id], c.rule.type)) {
			metricsFilled++;
		}
	}
	const filled = metadataFilled + metricsFilled;
	const total = PLOT_PROFILE_COMPLETENESS_METADATA_SLOTS + metricsTotal;
	const percentage = total === 0 ? 0 : Math.round((100 * filled) / total);
	return { filled, total, percentage };
}

